    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

pub(crate) fn strip_tool_markers(content: &str) -> String {
    if let Some(pos) = content.find("TOOL:") {
        let before = &content[..pos];
        return before.trim_end().to_string();
    }
    let mut result = String::new();
    for line in content.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with('{') {
            if let Ok(val) = serde_json::from_str::<serde_json::Value>(trimmed) {
                if val.get("name").is_some() && val.get("arguments").is_some() {
                    continue;
                }
            }
        }
        if !result.is_empty() {
            result.push('\n');
        }
        result.push_str(line);
    }
    result
}

pub(crate) fn content_has_tool_markers(content: &str) -> bool {
    if content.contains("TOOL:") {
        return true;
    }
    content.lines().any(|line| {
        let trimmed = line.trim();
        if !trimmed.starts_with('{') {
            return false;
        }
        serde_json::from_str::<serde_json::Value>(trimmed)
            .map(|v| v.get("name").is_some() && v.get("arguments").is_some())
            .unwrap_or(false)
    })
}

impl AppState {
    pub fn update(&mut self, event: Event) {
        if self.open_dialog.is_some() {
            self.update_dialog(event);
            return;
        }
        match event {
            Event::Input(c) => self.push_input(c),
            Event::Backspace => self.pop_input(),
            Event::Newline => self.insert_newline(),
            Event::CursorLeft => self.cursor_left(),
            Event::CursorRight => self.cursor_right(),
            Event::CursorStart => self.cursor_start(),
            Event::CursorEnd => self.cursor_end(),
            Event::DeleteWord => self.delete_word(),
            Event::DeleteToEnd => self.delete_to_end(),
            Event::DeleteToStart => self.delete_to_start(),
            Event::KillChar => self.kill_char(),
            Event::HistoryPrev => {
                if self.input.contains('\n') {
                    self.move_cursor_up();
                } else {
                    self.history_prev();
                }
            }
            Event::HistoryNext => {
                if self.input.contains('\n') {
                    self.move_cursor_down();
                } else {
                    self.history_next();
                }
            }
            Event::Undo => self.undo(),
            Event::Redo => self.redo(),
            Event::CursorWordLeft => self.cursor_word_left(),
            Event::CursorWordRight => self.cursor_word_right(),
            Event::Paste(text) => self.paste(&text),
            Event::Submit => self.submit(),
            Event::ScrollUp => {
                if self.messages.is_empty() && !self.turn_active {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_add(1);
            }
            Event::ScrollDown => {
                if self.scroll == 0 {
                    self.input_flash = 3;
                }
                self.scroll = self.scroll.saturating_sub(1);
            }
            Event::Quit => self.should_quit = true,
            Event::Reset => *self = AppState::default(),
            Event::AgentThinking { id } => {
                self.set_thinking(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentThoughtDone { id } => {
                self.add_thought(id);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolStart { id, name } => {
                self.start_tool(id, name);
                self.ensure_turn_complete_last();
            }
            Event::AgentToolEnd { duration_secs, output } => {
                self.end_tool(duration_secs, output);
                self.ensure_turn_complete_last();
            }
            Event::AgentResponse { id, content } => {
                self.append_response(id, content);
                self.ensure_turn_complete_last();
            }
            Event::AgentTurnComplete { id, duration_secs } => {
                self.complete_turn(id, duration_secs);
                self.ensure_turn_complete_last();
            }
            Event::AgentDone { id } => self.finish_turn(id),
            Event::AgentError { id, message } => {
                self.add_error(id, message);
                self.ensure_turn_complete_last();
            }
            Event::SwitchModel { provider, model } => self.switch_model(provider, model),
            Event::SwitchTheme { name } => self.switch_theme(name),
            Event::FollowUp => self.queue_follow_up(),
            Event::Dequeue => self.dequeue(),
            Event::OpenExternalEditor => {}
            Event::ExternalEditorDone { content } => {
                self.input = content;
                self.cursor_pos = self.input.len();
                self.mark_dirty();
            }
            Event::Abort => self.abort_queue(),
            Event::SpawnAgent => {}
            Event::ToggleExpand => self.toggle_expand_all(),
            Event::ToggleCommandPalette => {
                self.open_dialog = Some(crate::commands::DialogState::CommandPalette {
                    filter: String::new(),
                    selected: 0,
                });
                self.mark_dirty();
            }
            Event::PaletteFilter(_) |
            Event::PaletteBackspace |
            Event::PaletteUp |
            Event::PaletteDown |
            Event::PaletteSelect |
            Event::PaletteClose => {}
        }
    }

    fn update_dialog(&mut self, event: Event) {
        let Some(dialog) = self.open_dialog.take() else { return };
        match dialog {
            crate::commands::DialogState::CommandPalette { filter, selected } => {
                self.update_palette(event, filter, selected);
            }
            other => {
                self.open_dialog = Some(other);
            }
        }
    }

    fn update_palette(&mut self, event: Event, filter: String, selected: usize) {
        match event {
            Event::Abort | Event::PaletteClose | Event::ToggleCommandPalette => {
                self.open_dialog = None;
                self.mark_dirty();
            }
            Event::Input(c) | Event::PaletteFilter(c) => {
                self.palette_push_char(filter, c);
            }
            Event::Backspace | Event::PaletteBackspace => {
                self.palette_pop_char(filter);
            }
            Event::HistoryPrev | Event::PaletteUp => {
                self.palette_move_up(filter, selected);
            }
            Event::HistoryNext | Event::PaletteDown => {
                self.palette_move_down(filter, selected);
            }
            Event::Submit | Event::PaletteSelect => {
                self.palette_select(filter, selected);
            }
            _ => {
                self.set_palette(filter, selected);
            }
        }
    }

    fn palette_push_char(&mut self, mut filter: String, c: char) {
        filter.push(c);
        self.set_palette(filter, 0);
    }

    fn palette_pop_char(&mut self, mut filter: String) {
        filter.pop();
        self.set_palette(filter, 0);
    }

    fn palette_move_up(&mut self, filter: String, selected: usize) {
        let items = crate::commands::filter_commands(&self.registry, &filter);
        let new_sel = if selected == 0 {
            items.len().saturating_sub(1)
        } else {
            selected - 1
        };
        self.set_palette(filter, new_sel);
    }

    fn palette_move_down(&mut self, filter: String, selected: usize) {
        let items = crate::commands::filter_commands(&self.registry, &filter);
        let new_sel = if items.is_empty() {
            0
        } else {
            (selected + 1) % items.len()
        };
        self.set_palette(filter, new_sel);
    }

    fn palette_select(&mut self, filter: String, selected: usize) {
        let items = crate::commands::filter_commands(&self.registry, &filter);
        if let Some(cmd) = items.get(selected) {
            let result = (cmd.handler)(self, "");
            self.process_command_result(result);
        }
        self.open_dialog = None;
        self.mark_dirty();
    }

    fn set_palette(&mut self, filter: String, selected: usize) {
        self.open_dialog = Some(crate::commands::DialogState::CommandPalette {
            filter,
            selected,
        });
        self.mark_dirty();
    }

    fn process_command_result(&mut self, result: crate::commands::CommandResult) {
        match result {
            crate::commands::CommandResult::Message(msg) => self.add_system_msg(msg),
            crate::commands::CommandResult::Event(evt) => self.update(evt),
            crate::commands::CommandResult::OpenDialog(d) => {
                self.open_dialog = Some(match d {
                    crate::commands::Dialog::CommandPalette => {
                        crate::commands::DialogState::CommandPalette {
                            filter: String::new(),
                            selected: 0,
                        }
                    }
                    crate::commands::Dialog::ModelSelector => {
                        crate::commands::DialogState::ModelSelector {
                            filter: String::new(),
                            selected: 0,
                        }
                    }
                    crate::commands::Dialog::Settings => crate::commands::DialogState::Settings,
                });
                self.mark_dirty();
            }
            crate::commands::CommandResult::None => {}
        }
    }

    fn toggle_expand_all(&mut self) {
        self.all_collapsed = !self.all_collapsed;
        self.messages_changed();
    }

    fn switch_model(&mut self, provider: String, model: String) {
        self.current_provider = provider.clone();
        self.current_model = model.clone();
        self.add_system_msg(format!("Switched to {}/{}", provider, model));
    }

    fn switch_theme(&mut self, name: String) {
        self.theme_name = name.clone();
        self.add_system_msg(format!("Theme switched to '{}'", name));
    }

    pub fn peek_queue(&self) -> Option<&(String, String)> {
        self.request_queue.front()
    }

    pub fn pop_queue(&mut self) -> Option<(String, String)> {
        self.request_queue.pop_front()
    }

    fn add_system_msg(&mut self, content: String) {
        self.messages.push(ChatMessage {
            role: Role::System,
            content,
            timestamp: now(),
            id: "system".to_string(),
            ..Default::default()
        });
        self.messages_changed();
    }

    /// Move TurnComplete to the end of messages and bump its timestamp.
    /// Called after every agent event to ensure TurnComplete remains last.
    fn ensure_turn_complete_last(&mut self) {
        if let Some(idx) = self.messages.iter().position(|m| m.role == Role::TurnComplete) {
            let mut tc = self.messages.remove(idx);
            tc.timestamp = now();
            self.messages.push(tc);
            self.messages_changed();
        }
    }
}

use anyhow::Result;
use runie_core::event::Event;
use runie_core::provider::{Message, Provider};
use crate::parser::parse_tool_calls;
use crate::tools::Tool;
use crate::AgentCommand;
use std::time::Instant;

pub async fn run_agent_turn<F>(
    command: &AgentCommand,
    mut emit: F,
    max_iterations: usize,
) -> Result<()>
where
    F: FnMut(Event) + Send,
{
    let mut messages = build_initial_messages(command);
    let turn_start = Instant::now();
    let mut has_intermediate_steps = false;

    for _ in 0..max_iterations {
        emit(Event::AgentThinking { id: command.id.clone() });

        let mut response_text = String::new();
        let provider = crate::build_provider(&command.provider, &command.model);
        provider
            .generate(messages.clone(), |chunk| {
                response_text.push_str(&chunk.content);
                emit(Event::AgentResponse {
                    id: command.id.clone(),
                    content: chunk.content,
                });
            })
            .await?;

        emit(Event::AgentThoughtDone { id: command.id.clone() });

        let tools = parse_tool_calls(&response_text);
        if tools.is_empty() {
            break;
        }

        has_intermediate_steps = true;
        messages.push(Message::Assistant {
            content: response_text.clone(),
        });
        execute_tools(&command.id, &tools, &mut emit, &mut messages);
    }

    if has_intermediate_steps {
        emit(Event::AgentTurnComplete {
            id: command.id.clone(),
            duration_secs: turn_start.elapsed().as_secs_f64(),
        });
    }

    emit(Event::AgentDone { id: command.id.clone() });
    Ok(())
}

fn build_initial_messages(command: &AgentCommand) -> Vec<Message> {
    vec![
        Message::System {
            content: "You are a helpful assistant with access to tools. \
                Use structured JSON format: {\"name\": \"tool_name\", \"arguments\": {...}}. \
                Available tools: read_file, list_dir, write_file, edit_file, bash, grep, find. \
                Use edit_file for safe changes: {\"name\": \"edit_file\", \"arguments\": {\"path\": \"...\", \"search\": \"...\", \"replace\": \"...\"}}. \
                Use grep to search file contents: {\"name\": \"grep\", \"arguments\": {\"pattern\": \"...\", \"path\": \"...\"}}. \
                Use find to list files by pattern: {\"name\": \"find\", \"arguments\": {\"pattern\": \"...\", \"path\": \"...\"}}.".to_string(),
        },
        Message::User {
            content: command.content.clone(),
        },
    ]
}

fn execute_tools(
    cmd_id: &str,
    tools: &[Tool],
    emit: &mut dyn FnMut(Event),
    messages: &mut Vec<Message>,
) {
    for tool in tools {
        emit(Event::AgentToolStart {
            id: cmd_id.to_string(),
            name: tool.name().to_string(),
        });

        let tool_start = Instant::now();
        let result = tool.execute();
        let tool_elapsed = tool_start.elapsed().as_secs_f64();

        emit(Event::AgentToolEnd {
            duration_secs: tool_elapsed,
            output: result.output.clone(),
        });

        messages.push(Message::ToolResult {
            content: format!("{} result:\n{}", result.tool.name(), result.output),
        });
    }
}

//! Immutable frame description — the UI DSL.
//! The event loop builds snapshots; the render actor draws them.
//! Zero blocking I/O in the event loop by design.

use crate::model::VisibleRegion;
use crate::ui::elements::Element;

#[derive(Clone)]
pub struct Snapshot {
    pub elements: Vec<Element>,
    pub line_counts: Vec<usize>,
    pub total_lines: usize,
    pub input: String,
    pub cursor_pos: usize,
    pub hint_text: String,
    pub at_suggestions: Option<Vec<String>>,
    pub at_selected: Option<usize>,
    pub turn_active: bool,
    pub spinner_frame: char,
    pub scroll: usize,
    /// Elapsed seconds since turn started. Captured at snapshot creation time.
    pub turn_elapsed_secs: Option<f64>,
    pub provider: String,
    pub model: String,
    /// Active theme name for the render actor
    pub theme_name: String,
    /// Flash countdown for invalid input feedback.
    pub input_flash: u8,
    /// Placeholder text shown when input is empty.
    pub placeholder: String,
    /// Queue count (pending messages in queue)
    pub queue_count: usize,
    /// Currently open dialog state for rendering overlays.
    pub dialog: Option<crate::commands::DialogState>,
    /// Filtered command list for palette rendering (name, description, category).
    pub palette_items: Vec<(String, String, String)>,
}

impl Snapshot {
    pub fn element_count(&self) -> usize {
        self.elements.len()
    }

    pub fn visible(&self, skip: usize, take: usize) -> &[Element] {
        let start = skip.min(self.elements.len());
        let end = (start + take).min(self.elements.len());
        &self.elements[start..end]
    }

    pub fn visible_scroll(&self, visible_height: usize) -> VisibleRegion<'_> {
        if self.elements.is_empty() || visible_height == 0 {
            return VisibleRegion { elements: &[], skip_lines: 0 };
        }

        let total = self.total_lines;
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);

        let viewport_end = total.saturating_sub(scroll);
        let viewport_start = viewport_end.saturating_sub(visible_height);

        let mut cum = 0usize;
        let mut start_idx = 0;
        let mut skip_lines = 0;

        for (i, count) in self.line_counts.iter().enumerate() {
            let next_cum = cum + count;
            if next_cum > viewport_start {
                start_idx = i;
                skip_lines = viewport_start.saturating_sub(cum);
                break;
            }
            cum = next_cum;
        }

        let mut end_idx = self.elements.len();
        cum = 0;
        for (i, count) in self.line_counts.iter().enumerate() {
            cum += count;
            if cum >= viewport_end {
                end_idx = i + 1;
                break;
            }
        }

        VisibleRegion {
            elements: &self.elements[start_idx..end_idx.min(self.elements.len())],
            skip_lines,
        }
    }

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.total_lines.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        #[allow(clippy::manual_checked_ops)]
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }
}

